+        assert!(!result.contains('\u{009E}'));
+    }
+
+    #[test]
+    fn adversarial_c1_st_byte() {
+        // U+009C (ST = String Terminator)
+        let input = "A\u{009C}B";
+        let result = sanitize(input);
