+        let result = sanitize(input);
+        assert!(
+            matches!(result, Cow::Owned(_)),
+            "C1 should trigger slow path"
+        );
+        assert!(!result.contains('\u{0085}'));
+        assert_eq!(result.as_ref(), "cleantext");
